const rightPanel = document.getElementById('expandCardRightPanel');
if (!window.currentExpandCourseDay || window.currentExpandCourseDay !== `${courseName}-${dayId}`) {
    rightPanel.innerHTML = ''; // Reset panel only if card changed
    rightPanel._tabCaches = new Map();
    window.currentExpandCourseDay = `${courseName}-${dayId}`;
}
const tabCaches = rightPanel._tabCaches;

function showTab(cacheKey, createFunc) {
    Array.from(rightPanel.children).forEach(child => {
        // Pause YouTube videos using postMessage to prevent OS background media key issues without reloading iframe
        child.querySelectorAll('iframe').forEach(iframe => {
            const srcToCheck = iframe.dataset.originalSrc || iframe.src;
            if (srcToCheck && (srcToCheck.includes('youtube.com') || srcToCheck.includes('youtu.be'))) {
                iframe.contentWindow.postMessage('{"event":"command","func":"pauseVideo","args":""}', '*');
            }
        });
        child.style.display = 'none';
    });

    const cachedContainer = tabCaches.get(cacheKey);
    if (cachedContainer && rightPanel.contains(cachedContainer)) {
        cachedContainer.style.display = cachedContainer.dataset.displayType || 'block';
    } else {
        const container = createFunc();
        tabCaches.set(cacheKey, container);
        rightPanel.appendChild(container);
        // Save original display model so we securely toggle
        container.dataset.displayType = container.className === 'expand-iframe-container' ? 'flex' : 'block';
        container.style.display = container.dataset.displayType;
    }
}

function createVideoWrapper(link, embedUrl, currentCourseName, isCustom = false) {
    const wrapper = document.createElement('div');
    wrapper.className = 'video-embed-wrapper';
    wrapper.draggable = true;
    wrapper.dataset.link = link;

    if (!isCustom) {
        wrapper.addEventListener('contextmenu', (e) => {
            if (typeof showExpandResourceContextMenu === 'function') {
                showExpandResourceContextMenu(e, link, currentCourseName, dayId);
            }
        });
    }

    const iframe = document.createElement('iframe');
    iframe.className = 'video-embed-iframe';
    iframe.src = embedUrl;
    iframe.title = 'YouTube video player';
    iframe.setAttribute('frameborder', '0');
    iframe.allow = 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share';
    iframe.referrerPolicy = 'strict-origin-when-cross-origin';
    iframe.allowFullscreen = true;
    wrapper.appendChild(iframe);

    const dragHandle = document.createElement('div');
    dragHandle.className = 'video-drag-handle';
    dragHandle.innerHTML = '<svg viewBox="0 0 24 24" width="16" height="16" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><line x1="3" y1="12" x2="21" y2="12"></line><line x1="3" y1="6" x2="21" y2="6"></line><line x1="3" y1="18" x2="21" y2="18"></line></svg>';
    dragHandle.title = isCustom ? "Right-click to remove (if folder link), drag to reorder" : "Right-click to remove, drag to reorder";

    dragHandle.addEventListener('contextmenu', (e) => {
        e.stopPropagation();
        e.preventDefault();
        if (typeof showExpandResourceContextMenu === 'function') {
            showExpandResourceContextMenu(e, link, currentCourseName, dayId);
        }
    });
    wrapper.appendChild(dragHandle);

    wrapper.addEventListener('dragstart', (e) => {
        e.dataTransfer.effectAllowed = 'move';
        wrapper.classList.add('dragging');
        const grid = wrapper.closest('.expand-card-videos-grid');
        if (grid) grid.querySelectorAll('iframe').forEach(ifr => ifr.style.pointerEvents = 'none');
    });

    wrapper.addEventListener('dragend', () => {
        wrapper.classList.remove('dragging');
        const grid = wrapper.closest('.expand-card-videos-grid');
        if (grid) grid.querySelectorAll('iframe').forEach(ifr => ifr.style.pointerEvents = 'auto');
    });

    wrapper.addEventListener('dragover', (e) => {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'move';
        const grid = wrapper.closest('.expand-card-videos-grid');
        const draggingEle = grid ? grid.querySelector('.dragging') : null;
        if (draggingEle && draggingEle !== wrapper) {
            const children = Array.from(grid.children);
            const draggingIdx = children.indexOf(draggingEle);
            const targetIdx = children.indexOf(wrapper);

            if (draggingIdx < targetIdx) {
                wrapper.classList.add('drag-over-right');
                wrapper.classList.remove('drag-over-left');
            } else {
                wrapper.classList.add('drag-over-left');
                wrapper.classList.remove('drag-over-right');
            }
        }
    });

    wrapper.addEventListener('dragleave', () => {
        wrapper.classList.remove('drag-over-left', 'drag-over-right');
    });

    wrapper.addEventListener('drop', (e) => {
        e.preventDefault();
        wrapper.classList.remove('drag-over-left', 'drag-over-right');
        const grid = wrapper.closest('.expand-card-videos-grid');
        const draggingEle = grid ? grid.querySelector('.dragging') : null;
        if (draggingEle && draggingEle !== wrapper) {
            const children = Array.from(grid.children);
            const draggingIdx = children.indexOf(draggingEle);
            const targetIdx = children.indexOf(wrapper);

            if (draggingIdx < targetIdx) {
                wrapper.after(draggingEle);
            } else {
                wrapper.before(draggingEle);
            }

            const newOrder = Array.from(grid.querySelectorAll('.video-embed-wrapper')).map(w => w.dataset.link);
            let savedOrder = {};
            const savedOrderStr = localStorage.getItem('expandOrder_' + currentCourseName);
            if (savedOrderStr) {
                try { savedOrder = JSON.parse(savedOrderStr); } catch (err) { }
            }
            // Merge: preserve ordering of videos outside this subgroup
            const existingOrder = Array.isArray(savedOrder.youtubeLinks) ? savedOrder.youtubeLinks : [];
            const filtered = existingOrder.filter(link => !newOrder.includes(link));
            // Find insertion point: where the first item of newOrder was in the old list
            const firstInOld = existingOrder.indexOf(newOrder[0]);
            const insertIdx = firstInOld !== -1 ? filtered.findIndex((_, i) => i >= firstInOld) : filtered.length;
            const mergedOrder = [...filtered.slice(0, insertIdx === -1 ? filtered.length : insertIdx), ...newOrder, ...filtered.slice(insertIdx === -1 ? filtered.length : insertIdx)];
            savedOrder.youtubeLinks = mergedOrder;
            localStorage.setItem('expandOrder_' + currentCourseName, JSON.stringify(savedOrder));
        }
    });

    return wrapper;
}

function renderVideoTab() {
    showTab('youtube', () => {
        const container = document.createElement('div');
        container.className = 'expand-videos-container';

        const titleEl = document.createElement('div');
        titleEl.className = 'expand-card-videos-title';
        titleEl.textContent = 'YouTube Videos';
        container.appendChild(titleEl);

        const grid = document.createElement('div');
        grid.className = 'expand-card-videos-grid';

        youtubeLinks.forEach(({ link, embedUrl }) => {
            const isCustom = customLinksList.includes(link);
            const wrapper = createVideoWrapper(link, embedUrl, courseName, isCustom);
            grid.appendChild(wrapper);
        });

        container.appendChild(grid);
        return container;
    });
}

function renderSiteTab(url, rawLink) {
    showTab(url, () => {
        const wrapper = document.createElement('div');
        wrapper.className = 'expand-iframe-container';

        const iframe = document.createElement('iframe');
        iframe.className = 'expand-preview-iframe';
        iframe.src = url;
        iframe.title = 'Website preview';
        iframe.loading = 'lazy';

        wrapper.appendChild(iframe);
        return wrapper;
    });
}

