            item.addEventListener('dragend', () => {
                item.classList.remove('dragging-nav');
                item.style.opacity = '1';
            });

            item.addEventListener('dragover', (e) => {
                e.preventDefault();
                e.dataTransfer.dropEffect = 'move';
                const container = item.parentElement;
                const draggingEle = container.querySelector('.dragging-nav');
                if (draggingEle && draggingEle !== item) {
                    const children = Array.from(container.children);
                    const draggingIdx = children.indexOf(draggingEle);
                    const targetIdx = children.indexOf(item);

                    // Reset first to avoid double lines
                    item.style.borderTop = '';
                    item.style.borderBottom = '';
                    item.style.borderTopLeftRadius = '';
                    item.style.borderTopRightRadius = '';
                    item.style.borderBottomLeftRadius = '';
                    item.style.borderBottomRightRadius = '';

                    if (draggingIdx < targetIdx) {
                        item.style.borderBottom = '2px solid #007bff';
                        item.style.borderBottomLeftRadius = '0';
                        item.style.borderBottomRightRadius = '0';
                    } else {
                        item.style.borderTop = '2px solid #007bff';
                        item.style.borderTopLeftRadius = '0';
                        item.style.borderTopRightRadius = '0';
                    }
                }
            });

            item.addEventListener('dragleave', () => {
                item.style.borderTop = '';
                item.style.borderBottom = '';
                item.style.borderTopLeftRadius = '';
                item.style.borderTopRightRadius = '';
                item.style.borderBottomLeftRadius = '';
                item.style.borderBottomRightRadius = '';
            });

            item.addEventListener('drop', (e) => {
                e.preventDefault();
                item.style.borderTop = '';
                item.style.borderBottom = '';
                item.style.borderTopLeftRadius = '';
                item.style.borderTopRightRadius = '';
                item.style.borderBottomLeftRadius = '';
                item.style.borderBottomRightRadius = '';

                const container = item.parentElement;
                const draggingEle = container.querySelector('.dragging-nav');
                if (draggingEle && draggingEle !== item) {
                    const children = Array.from(container.children);
                    const draggingIdx = children.indexOf(draggingEle);
                    const targetIdx = children.indexOf(item);

                    if (draggingIdx < targetIdx) item.after(draggingEle);
                    else item.before(draggingEle);

                    // Rebuild and save the master array by capturing DOM order across all groups globally
                    const allNavItems = Array.from(document.querySelectorAll('.expand-nav-item[data-link]'));
                    const newOrder = allNavItems.map(el => el.dataset.link);

                    let savedOrder = {};
                    try { savedOrder = JSON.parse(localStorage.getItem('expandOrder_' + courseName)) || {}; } catch (err) { }
                    savedOrder.textLinks = newOrder;
                    localStorage.setItem('expandOrder_' + courseName, JSON.stringify(savedOrder));
                }
            });

            item.addEventListener('contextmenu', (e) => {
                if (typeof showExpandResourceContextMenu === 'function') {
                    showExpandResourceContextMenu(e, link, courseName, dayId);
                }
            });

            item.addEventListener('click', () => {
                document.querySelectorAll('button.expand-nav-item').forEach(el => {
                    el.classList.remove('active');
                    el.setAttribute('aria-selected', 'false');
                });
                item.classList.add('active');
                item.setAttribute('aria-selected', 'true');
                window.currentExpandActiveTabId = link;
                if (isYt) {
                    renderSiteTab(getYouTubeEmbed(link), link);
                } else {
                    renderSiteTab(displayUrl, link);
                }
            });

            return { element: item, isYt, displayUrl, link };
        }

        // Helper: create a YouTube grid button for a group
        function createGroupYoutubeGridBtn(groupYtLinks, groupTitle) {
            const item = document.createElement('button');
            item.type = 'button';
            item.role = 'tab';
            item.className = 'expand-nav-item' + (isFirst ? ' active' : '');
            if (isFirst) item.setAttribute('aria-selected', 'true');
            item.innerHTML = `${videoSvg} YouTube Videos`;

            const renderGroupGrid = () => {
                showTab('youtube-' + groupTitle, () => {
                    const container = document.createElement('div');
                    container.className = 'expand-videos-container';
                    const titleEl = document.createElement('div');
                    titleEl.className = 'expand-card-videos-title';
                    titleEl.textContent = groupTitle + ' — YouTube Videos';
                    container.appendChild(titleEl);
                    const grid = document.createElement('div');
                    grid.className = 'expand-card-videos-grid';
                    groupYtLinks.forEach(({ link, embedUrl }) => {
                        const isCustom = customLinksList.includes(link) || lessonLinksList.some(l => l.url === link);
                        const wrapper = createVideoWrapper(link, embedUrl, courseName, isCustom);
                        grid.appendChild(wrapper);
                    });
                    container.appendChild(grid);
                    return container;
                });
            };

            item.addEventListener('click', () => {
                document.querySelectorAll('button.expand-nav-item').forEach(el => {
                    el.classList.remove('active');
                    el.setAttribute('aria-selected', 'false');
                });
                item.classList.add('active');
                item.setAttribute('aria-selected', 'true');
                window.currentExpandActiveTabId = 'youtube-' + groupTitle;
                renderGroupGrid();
            });

            return { element: item, render: renderGroupGrid };
        }

        // Helper: render a collapsible group
        function renderCollapsibleGroup(title, items, groupYtLinks, isCustomFolder = false, defaultCollapsed = false) {
            const hasItems = items.length > 0 || groupYtLinks.length > 0;
            if (!hasItems && !isCustomFolder) return;

            const groupWrapper = document.createElement('div');
            groupWrapper.className = 'expand-nav-group';
            groupWrapper.style.marginTop = '10px';
            if (isCustomFolder) {
                groupWrapper.style.marginLeft = '12px';
                groupWrapper.style.borderLeft = '2px solid #eee';
                groupWrapper.style.paddingLeft = '10px';
            }

            const header = document.createElement('div');
            header.className = 'expand-nav-group-header';
            header.innerHTML = `<span class="expand-nav-group-arrow">&#9660;</span> ${title}`;
            header.style.cssText = 'cursor:pointer; user-select:none; padding:8px 10px; font-size:11px; text-transform:uppercase; color:#555; font-weight:bold; letter-spacing:0.5px; display:flex; align-items:center; gap:6px; border-radius:6px; transition:background 0.15s;';
            header.addEventListener('mouseenter', () => header.style.background = 'rgba(0,0,0,0.04)');
            header.addEventListener('mouseleave', () => header.style.background = '');

            const content = document.createElement('div');
            content.className = 'expand-nav-group-content';
            content.style.cssText = 'overflow:hidden; transition:max-height 0.3s ease;';

            const arrow = header.querySelector('.expand-nav-group-arrow');
            arrow.style.cssText = 'display:inline-block; transition:transform 0.25s ease; font-size:9px;';

            const groupStateKey = `${title}`;
            let collapsed = window.expandGroupStates[groupStateKey] !== undefined ? window.expandGroupStates[groupStateKey] : defaultCollapsed;

            if (collapsed) {
                content.style.maxHeight = '0';
                arrow.style.transform = 'rotate(-90deg)';
            } else {
                // Delay reading scrollHeight slightly or just set to a large value temporarily since it's not DOM yet
                content.style.maxHeight = '500px'; 
            }

            header.addEventListener('click', (e) => {
                if (e.target.tagName.toLowerCase() === 'input' || e.target.closest('.folder-add-link-container')) return;
                collapsed = !collapsed;
                window.expandGroupStates[groupStateKey] = collapsed;
                if (collapsed) {
                    content.style.maxHeight = '0';
                    arrow.style.transform = 'rotate(-90deg)';
                } else {
                    content.style.maxHeight = content.scrollHeight + 'px';
                    arrow.style.transform = 'rotate(0deg)';
                }
            });

            if (isCustomFolder) {
                header.addEventListener('contextmenu', (e) => {
                    e.preventDefault();
                    expandFolderContextData = { folderName: title, courseName, dayId, groupWrapper, content, collapsed, header, arrow };

                    expandFolderContextMenu.style.display = 'block';
                    const menuRect = expandFolderContextMenu.getBoundingClientRect();
                    let left = e.clientX;
                    let top = e.clientY;
                    if (left + menuRect.width > window.innerWidth) left = window.innerWidth - menuRect.width - 10;
                    if (top + menuRect.height > window.innerHeight) top = window.innerHeight - menuRect.height - 10;
                    expandFolderContextMenu.style.left = `${left}px`;
                    expandFolderContextMenu.style.top = `${top}px`;
                });
                header.title = "Right-click for options";
            }

            groupWrapper.appendChild(header);

            // Add per-group YouTube grid button if this group has YT links
            if (groupYtLinks.length > 0) {
                const ytBtn = createGroupYoutubeGridBtn(groupYtLinks, title);
                content.appendChild(ytBtn.element);
            }

            // Add individual link items
            items.forEach(itemData => {
                const { element, isYt, displayUrl, link } = createLinkNavItem(itemData);
                if (isYt) return; // Skip rendering individual YouTube links (handled by grid)

                content.appendChild(element);
            });

            groupWrapper.appendChild(content);
            navList.appendChild(groupWrapper);
        }

        // --- Ordered groups: Current Day Links → Lesson Links → Media → Folders → Course Links ---
        renderCollapsibleGroup('Current Day Links', dayLinkItems, dayYoutubeLinks);
        renderCollapsibleGroup('Lesson Links', lessonLinkItems, lessonYoutubeLinks);

        // Render custom folders BEFORE media
        Object.keys(customFolders).forEach(fName => {
            const items = folderLinkItems[fName] || [];
            const ytLinks = getGroupYoutubeLinks(items);
            renderCollapsibleGroup(fName, items, ytLinks, true);
        });

        // --- MEDIA group (master YouTube grid with ALL videos) ---
        if (youtubeLinks.length > 0) {
            const groupWrapper = document.createElement('div');
            groupWrapper.className = 'expand-nav-group';

            const header = document.createElement('div');
            header.className = 'expand-nav-group-header';
            header.innerHTML = `<span class="expand-nav-group-arrow">&#9660;</span> Media`;
            header.style.cssText = 'cursor:pointer; user-select:none; padding:8px 10px; margin-top:10px; font-size:11px; text-transform:uppercase; color:#555; font-weight:bold; letter-spacing:0.5px; display:flex; align-items:center; gap:6px; border-radius:6px; transition:background 0.15s;';
            header.addEventListener('mouseenter', () => header.style.background = 'rgba(0,0,0,0.04)');
            header.addEventListener('mouseleave', () => header.style.background = '');

            const content = document.createElement('div');
            content.className = 'expand-nav-group-content';
            content.style.cssText = 'overflow:hidden; transition:max-height 0.3s ease; max-height:0;';

            const arrow = header.querySelector('.expand-nav-group-arrow');
            arrow.style.cssText = 'display:inline-block; transition:transform 0.25s ease; font-size:9px; transform:rotate(-90deg);';

            const groupStateKey = 'Media';
            let collapsed = window.expandGroupStates[groupStateKey] !== undefined ? window.expandGroupStates[groupStateKey] : true;

            if (collapsed) {
                content.style.maxHeight = '0';
                arrow.style.transform = 'rotate(-90deg)';
            } else {
                content.style.maxHeight = '500px';
                arrow.style.transform = 'rotate(0deg)';
            }

            header.addEventListener('click', () => {
                collapsed = !collapsed;
                window.expandGroupStates[groupStateKey] = collapsed;
                if (collapsed) {
                    content.style.maxHeight = '0';
                    arrow.style.transform = 'rotate(-90deg)';
                } else {
                    content.style.maxHeight = content.scrollHeight + 'px';
                    arrow.style.transform = 'rotate(0deg)';
                }
            });

            groupWrapper.appendChild(header);

            const item = document.createElement('button');
            item.type = 'button';
            item.role = 'tab';
            item.className = 'expand-nav-item' + (isFirst ? ' active' : '');
            if (isFirst) item.setAttribute('aria-selected', 'true');
            item.innerHTML = `${videoSvg} All YouTube Videos`;
            item.addEventListener('click', () => {
                document.querySelectorAll('button.expand-nav-item').forEach(el => {
                    el.classList.remove('active');
                    el.setAttribute('aria-selected', 'false');
                });
                item.classList.add('active');
                item.setAttribute('aria-selected', 'true');
                window.currentExpandActiveTabId = 'youtube-all';
                renderVideoTab();
            });
            content.appendChild(item);

            groupWrapper.appendChild(content);
            navList.appendChild(groupWrapper);
        }

        // (Custom folders were moved above Media)

        renderCollapsibleGroup('Course Links', courseLinkItems, courseYoutubeLinks, false, true);

        // Restore active tab
        if (window.currentExpandActiveTabId) {
            const allNavBtns = document.querySelectorAll('button.expand-nav-item');
            let found = false;
            allNavBtns.forEach(btn => {
                if (btn.dataset.link === window.currentExpandActiveTabId) {
                    btn.click();
                    found = true;
                }
            });
            // check youtube tabs
            if (!found) {
                allNavBtns.forEach(btn => {
                    if (window.currentExpandActiveTabId === 'youtube-all' && btn.innerText.includes('All YouTube')) {
                        btn.click();
                        found = true;
                    } else if (window.currentExpandActiveTabId.startsWith('youtube-') && btn.innerText.includes('YouTube Videos') && btn.closest('.expand-nav-group')) {
                        const titleNode = btn.closest('.expand-nav-group').querySelector('.expand-nav-group-header');
                        if (titleNode && window.currentExpandActiveTabId === 'youtube-' + titleNode.innerText.replace('▼','').trim()) {
                            btn.click();
                            found = true;
                        }
                    }
                });
            }
            if (!found && allNavBtns.length > 0) {
                allNavBtns[0].click();
            }
        } else {
            const firstNav = document.querySelector('button.expand-nav-item');
            if (firstNav) firstNav.click();
        }

    } else {
        rightPanel.innerHTML = '<div style="padding: 28px 32px; color: #999; font-style: italic;">No linked resources available.</div>';
    }

    // Focus management: save previous focus, show dialog, focus close button
    expandCardPreviousFocus = document.activeElement;
    expandCardOverlay.classList.add('active');

    // Adjust textarea heights now that the overlay is visible (display: block) and scrollHeight is > 0
    expandCardBody.querySelectorAll('textarea.expand-sync-target').forEach(ta => {
        autoResizeTextarea(ta);
    });

    expandCardClose.focus();
}

let expandCardPreviousFocus = null;

function closeExpandCard() {
    expandCardOverlay.classList.remove('active');

    // Clear the right panel so videos stop playing and iframes are unloaded
    const rightPanel = document.getElementById('expandCardRightPanel');
    if (rightPanel) {
        rightPanel.innerHTML = '';
        rightPanel._tabCaches = new Map();
    }
    window.currentExpandCourseDay = null;
    window.expandGroupStates = {};

    // Restore previous focus
    if (expandCardPreviousFocus && expandCardPreviousFocus.focus) {
        expandCardPreviousFocus.focus();
        expandCardPreviousFocus = null;
    }
}

// Helper: escape HTML to prevent injection
function escapeHTML(str) {
    const div = document.createElement('div');
    div.textContent = str;
    return div.innerHTML;
}

expandCardClose.addEventListener('click', closeExpandCard);
expandCardRefresh.addEventListener('click', () => {
    const rightPanel = document.getElementById('expandCardRightPanel');
    if (rightPanel) {
        const activeTab = Array.from(rightPanel.children).find(child => child.style.display !== 'none');
        if (activeTab) {
            const iframes = activeTab.querySelectorAll('iframe');
            iframes.forEach(iframe => {
                iframe.src = iframe.src;
            });
        }
    }

