.video-embed-wrapper {
    position: relative;
    padding-bottom: 56.25%;
    height: 0;
    overflow: hidden;
    border-radius: 12px;
    transform: translateZ(0);
    /* Removed margin-bottom here, added inline in JS for flexibility */
}

.video-embed-wrapper iframe {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    border: none;
}

.video-drag-handle {
    position: absolute;
    top: 8px;
    right: 8px;
    width: 32px;
    height: 32px;
    background: rgba(0, 0, 0, 0.6);
    color: white;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    cursor: grab;
    z-index: 10;
    opacity: 0;
    transition: opacity 0.2s;
}

.video-embed-wrapper:hover .video-drag-handle {
    opacity: 1;
}

.video-drag-handle:active {
    cursor: grabbing;
}

.video-embed-wrapper.dragging {
    opacity: 0.5;
}

.video-embed-wrapper.drag-over-left {
    box-shadow: -4px 0 0 #3498db, 0 4px 6px rgba(0, 0, 0, 0.1);
}

.video-embed-wrapper.drag-over-right {
    box-shadow: 4px 0 0 #3498db, 0 4px 6px rgba(0, 0, 0, 0.1);
}


.course-embed-container a {
    display: block;

