    align-items: center;
    gap: 10px;
    border: 1px solid transparent;
    user-select: none;
}

button.expand-nav-item:hover {
    background-color: #f0f0f0;
}

button.expand-nav-item.active {
    background-color: var(--chip-bg, #f0f8ff);
