    border: none;
    display: block;
    background-color: #fff;
}

.expand-preview-url-bar {
    padding: 12px 28px;
    background-color: #f8f8f8;
    border-bottom: 1px solid #e0e0e0;
    font-size: 13px;
    display: flex;
    align-items: center;
    gap: 8px;
}

.expand-preview-url-bar a {
    color: var(--active-color);
    text-decoration: none;
    font-weight: 600;
}

.expand-preview-url-bar a:hover {
    text-decoration: underline;
}

