/* --- Expand Card Modal (Full-Screen Two-Column, Claymorphism) --- */
.expand-card-overlay {
    display: none;
    position: fixed;
    top: 0;
    left: 0;
    right: 0;
    bottom: 0;
    background: linear-gradient(160deg, #eef2f9 0%, #e6ecf6 55%, #e9eef7 100%);
    z-index: 3000;
    flex-direction: row;
    animation: expandFadeIn 0.2s ease-out;
}

.expand-card-overlay.active {
    display: flex;
}

@keyframes expandFadeIn {
    from {
        opacity: 0;
    }

    to {
        opacity: 1;
    }
}

/* Left sidebar shell */
.expand-card-sidebar {
    flex: 0 0 340px;
    display: flex;
    flex-direction: column;
    background: linear-gradient(180deg, #ffffff 0%, #fbfcfe 100%);
    box-shadow: 4px 0 30px rgba(90, 110, 150, 0.12);
    position: relative;
    z-index: 1;
}

.expand-card-sidebar-head {
    padding: 26px 26px 14px;
    flex-shrink: 0;
}

.expand-card-eyebrow {
    font-size: 11px;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 1.4px;
    color: #aab2c4;
    margin-bottom: 4px;
}

.expand-card-title-row {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: 12px;
}

.expand-card-title-row h2 {
    font-size: 23px;
    font-weight: 700;
    margin: 0;
    color: var(--active-color);
    line-height: 1.2;
    flex: 1;
    min-width: 0;
}

.expand-card-head-actions {
    display: flex;
    gap: 8px;
    align-items: center;
    flex-shrink: 0;
}

.expand-card-close, .expand-card-refresh {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    border: 1px solid var(--clay-border);
    background: #ffffff;
    color: #6b7488;
    font-size: 19px;
    font-weight: 600;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: box-shadow 0.18s ease, transform 0.18s ease, color 0.18s ease;
    font-family: Arial, sans-serif;
    line-height: 1;
    padding: 0;
    box-shadow: 0 3px 8px rgba(90, 110, 150, 0.14);
}

.expand-card-close:hover, .expand-card-refresh:hover {
    color: var(--active-color);
    transform: translateY(-1px);
    box-shadow: 0 5px 12px rgba(90, 110, 150, 0.20);
}

.expand-card-body {
    flex: 1;
    padding: 6px 22px 22px;
    overflow-y: auto;
}

