item.appendChild(handle);

// Setup dragging
item.draggable = true;

item.addEventListener('dragstart', (e) => {
    e.dataTransfer.effectAllowed = 'move';
    item.classList.add('dragging-nav');
    item.style.opacity = '0.5';
});

item.addEventListener('dragend', () => {
    item.classList.remove('dragging-nav');
    item.style.opacity = '1';
});

item.addEventListener('dragover', (e) => {
    e.preventDefault();
    e.dataTransfer.dropEffect = 'move';
    const container = item.parentElement;
    const draggingEle = container.querySelector('.dragging-nav');
    if (draggingEle && draggingEle !== item) {
        const children = Array.from(container.children);
        const draggingIdx = children.indexOf(draggingEle);
        const targetIdx = children.indexOf(item);

        // Reset first to avoid double lines
        item.style.borderTop = '';
        item.style.borderBottom = '';
        item.style.borderTopLeftRadius = '';
        item.style.borderTopRightRadius = '';
        item.style.borderBottomLeftRadius = '';
        item.style.borderBottomRightRadius = '';

        if (draggingIdx < targetIdx) {
            item.style.borderBottom = '2px solid #007bff';
            item.style.borderBottomLeftRadius = '0';
            item.style.borderBottomRightRadius = '0';
        } else {
            item.style.borderTop = '2px solid #007bff';
            item.style.borderTopLeftRadius = '0';
            item.style.borderTopRightRadius = '0';
        }
    }
});

