/* --- Featured YouTube player layout --- */
.expand-featured-player-section {
    margin-bottom: 22px;
}

.expand-featured-player {
    position: relative;
    padding-bottom: 56.25%;
    height: 0;
    overflow: hidden;
    border-radius: 16px;
    background: #0f1115;
    box-shadow: 0 10px 28px rgba(80, 100, 140, 0.18), 0 2px 6px rgba(80, 100, 140, 0.10);
}

.expand-featured-player iframe {
    position: absolute;
    top: 0; left: 0;
    width: 100%; height: 100%;
    border: none;
}

.expand-featured-meta {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 14px 2px 0;
    gap: 14px;
}

.expand-featured-title-group {
    flex: 1;
    min-width: 0;
}

.expand-featured-title {
    font-size: 16px;
    font-weight: 700;
    color: #2c3340;
    margin-bottom: 3px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.expand-featured-channel {
    font-size: 13px;
    color: #8b94a8;
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.expand-featured-watch-link {
    display: inline-flex;
    align-items: center;
    gap: 7px;
    padding: 9px 16px;
    border-radius: 50px;
    border: 1.5px solid var(--clay-border);
    background: #ffffff;
    color: var(--active-color);
    font-size: 13px;
    font-weight: 600;
    font-family: inherit;
    text-decoration: none;
    cursor: pointer;
    box-shadow: 0 3px 8px rgba(90, 110, 150, 0.10);
    transition: box-shadow 0.18s ease, transform 0.18s ease;
    white-space: nowrap;
    flex-shrink: 0;
}

.expand-featured-watch-link:hover {
    box-shadow: 0 6px 16px rgba(90, 110, 150, 0.18);
    transform: translateY(-1px);
}

/* Thumbnail strip below featured player */
.expand-video-thumb-strip {
    display: flex;
    gap: 14px;
    flex-wrap: wrap;
}

.expand-video-thumb-card {
    flex: 0 0 calc(33.333% - 10px);
    cursor: pointer;
    border-radius: 14px;
    overflow: hidden;
    border: 2px solid transparent;
    background: var(--clay-surface);
    box-shadow: 0 4px 12px rgba(90, 110, 150, 0.10);
    transition: box-shadow 0.18s ease, transform 0.18s ease, border-color 0.18s ease;
}

.expand-video-thumb-card:hover {
    transform: translateY(-2px);
    box-shadow: 0 8px 20px rgba(90, 110, 150, 0.16);
}

.expand-video-thumb-card.active {
    border-color: var(--active-color);
    box-shadow: 0 4px 16px rgba(90, 110, 150, 0.18);
}

.expand-video-thumb-img {
    width: 100%;
    padding-bottom: 56.25%;
    background-size: cover;
    background-position: center;
    background-color: #1a1d24;
    background-repeat: no-repeat;
}

.expand-video-thumb-meta {
    padding: 10px 12px 12px;
}

