function buildYouTubeFeaturedLayout(container, ytLinks) {
    if (!ytLinks || ytLinks.length === 0) return;

    function getVideoId(embedUrl) {
        const m = embedUrl.match(/\/embed\/([^?&#/]+)/);
        return m ? m[1] : null;
    }

    let activeIdx = 0;

    // Featured player
    const featuredSection = document.createElement('div');
    featuredSection.className = 'expand-featured-player-section';

    const featuredPlayerDiv = document.createElement('div');
    featuredPlayerDiv.className = 'expand-featured-player';

    const featuredIframe = document.createElement('iframe');
    featuredIframe.src = ytLinks[0].embedUrl;
    featuredIframe.title = 'YouTube video player';
    featuredIframe.setAttribute('frameborder', '0');
    featuredIframe.allow = 'accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share';
    featuredIframe.referrerPolicy = 'strict-origin-when-cross-origin';
    featuredIframe.allowFullscreen = true;
    featuredPlayerDiv.appendChild(featuredIframe);
    featuredSection.appendChild(featuredPlayerDiv);

    // Meta bar below featured player
    const metaBar = document.createElement('div');
    metaBar.className = 'expand-featured-meta';

    const titleGroup = document.createElement('div');
    titleGroup.className = 'expand-featured-title-group';

    const featuredTitleEl = document.createElement('div');
    featuredTitleEl.className = 'expand-featured-title';
    featuredTitleEl.textContent = 'YouTube Video';

    const featuredChannelEl = document.createElement('div');
    featuredChannelEl.className = 'expand-featured-channel';

    titleGroup.appendChild(featuredTitleEl);
    titleGroup.appendChild(featuredChannelEl);
    metaBar.appendChild(titleGroup);

    const watchLink = document.createElement('a');
    watchLink.className = 'expand-featured-watch-link';
    watchLink.href = ytLinks[0].link.startsWith('http') ? ytLinks[0].link : 'https://' + ytLinks[0].link;
    watchLink.target = '_blank';
    watchLink.rel = 'noopener noreferrer';
    watchLink.innerHTML = `<svg viewBox="0 0 24 24" width="14" height="14" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><path d="M18 13v6a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V8a2 2 0 0 1 2-2h6"></path><polyline points="15 3 21 3 21 9"></polyline><line x1="10" y1="14" x2="21" y2="3"></line></svg> Watch on YouTube`;
    metaBar.appendChild(watchLink);

    featuredSection.appendChild(metaBar);
    container.appendChild(featuredSection);

    // Thumbnail strip (only when there are multiple videos)
    const thumbCards = [];
    if (ytLinks.length > 1) {
        const strip = document.createElement('div');
        strip.className = 'expand-video-thumb-strip';

        ytLinks.forEach(({ link, embedUrl }, idx) => {
            const vid = getVideoId(embedUrl);
            const thumbUrl = vid ? `https://img.youtube.com/vi/${vid}/hqdefault.jpg` : '';

            const card = document.createElement('div');
            card.className = 'expand-video-thumb-card' + (idx === 0 ? ' active' : '');
            card.dataset.idx = String(idx);

            const thumbImgDiv = document.createElement('div');
            thumbImgDiv.className = 'expand-video-thumb-img';
            if (thumbUrl) thumbImgDiv.style.backgroundImage = `url('${thumbUrl}')`;
            card.appendChild(thumbImgDiv);

            const thumbMetaDiv = document.createElement('div');
            thumbMetaDiv.className = 'expand-video-thumb-meta';

            const thumbTitleEl = document.createElement('div');
            thumbTitleEl.className = 'expand-video-thumb-title';
            thumbTitleEl.textContent = '—';

            const thumbChannelEl = document.createElement('div');
            thumbChannelEl.className = 'expand-video-thumb-channel';

            thumbMetaDiv.appendChild(thumbTitleEl);
            thumbMetaDiv.appendChild(thumbChannelEl);
            card.appendChild(thumbMetaDiv);
            thumbCards.push({ card, thumbTitleEl, thumbChannelEl });

            card.addEventListener('contextmenu', (e) => {
                if (typeof showExpandResourceContextMenu === 'function') {
                    showExpandResourceContextMenu(e, link, courseName, dayId);
                }
            });

            card.addEventListener('click', () => {
                if (activeIdx === idx) return;
                activeIdx = idx;
                featuredIframe.src = embedUrl;
                watchLink.href = link.startsWith('http') ? link : 'https://' + link;
                featuredTitleEl.textContent = thumbTitleEl.textContent !== '—' ? thumbTitleEl.textContent : 'YouTube Video';
                featuredChannelEl.textContent = thumbChannelEl.textContent;
                strip.querySelectorAll('.expand-video-thumb-card').forEach(c => c.classList.remove('active'));
                card.classList.add('active');
            });

            strip.appendChild(card);
        });

        container.appendChild(strip);
    }

    // Async: fetch video title + channel from YouTube oEmbed (no API key needed)
    ytLinks.forEach(({ link, embedUrl }, idx) => {
        const vid = getVideoId(embedUrl);
        if (!vid) return;
        fetch(`https://www.youtube.com/oembed?url=https://www.youtube.com/watch?v=${encodeURIComponent(vid)}&format=json`, { mode: 'cors' })
            .then(r => { if (!r.ok) throw new Error(); return r.json(); })
            .then(data => {
                const title = data.title || 'YouTube Video';
                const channel = data.author_name || '';
                if (idx === activeIdx) {
                    featuredTitleEl.textContent = title;
                    featuredChannelEl.textContent = channel;
                }
                if (thumbCards[idx]) {
                    thumbCards[idx].thumbTitleEl.textContent = title;
                    thumbCards[idx].thumbChannelEl.textContent = channel;
                }
            })
            .catch(() => {
                if (idx === 0) featuredTitleEl.textContent = 'YouTube Video';
                if (thumbCards[idx]) thumbCards[idx].thumbTitleEl.textContent = 'YouTube Video';
            });
    });
}

