const rightPanel = document.getElementById('expandCardRightPanel');
rightPanel.innerHTML = '';
rightPanel._tabCaches = new Map();
window.currentExpandCourseDay = `${courseName}-${dayId}`;
const tabCaches = rightPanel._tabCaches;

function showTab(cacheKey, createFunc) {
    Array.from(rightPanel.children).forEach(child => {
        // Pause YouTube videos using postMessage to prevent OS background media key issues without reloading iframe
        child.querySelectorAll('iframe').forEach(iframe => {
            const srcToCheck = iframe.dataset.originalSrc || iframe.src;
            if (srcToCheck && (srcToCheck.includes('youtube.com') || srcToCheck.includes('youtu.be'))) {
                iframe.contentWindow.postMessage('{"event":"command","func":"pauseVideo","args":""}', '*');
            }
        });
        child.style.display = 'none';
    });

    const cachedContainer = tabCaches.get(cacheKey);
    if (cachedContainer && rightPanel.contains(cachedContainer)) {
        cachedContainer.style.display = cachedContainer.dataset.displayType || 'block';
    } else {
        const container = createFunc();
        tabCaches.set(cacheKey, container);
        rightPanel.appendChild(container);
        // Save original display model so we securely toggle
        container.dataset.displayType = container.className === 'expand-iframe-container' ? 'flex' : 'block';
        container.style.display = container.dataset.displayType;
    }
}

function createVideoWrapper(link, embedUrl, currentCourseName, isCustom = false) {
    const wrapper = document.createElement('div');
    wrapper.className = 'video-embed-wrapper';
    wrapper.draggable = true;
    wrapper.dataset.link = link;

    if (!isCustom) {
        wrapper.addEventListener('contextmenu', (e) => {
            if (typeof showExpandResourceContextMenu === 'function') {
                showExpandResourceContextMenu(e, link, currentCourseName, dayId);
            }
        });
    }

